#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_CITIES 50
#define MAX_ROADS 2500
#define MAX_ROUTE_LENGTH 50
#define MAX_CITY_NAME_LENGTH 20

// Structure to represent a road
typedef struct {
    char city1[MAX_CITY_NAME_LENGTH];
    char city2[MAX_CITY_NAME_LENGTH];
    int length;
} Road;

// Structure to represent a graph
typedef struct {
    char cities[MAX_CITIES][MAX_CITY_NAME_LENGTH];
    Road roads[MAX_ROADS];
    int numCities;
    int numRoads;
} Graph;

// Function to create a new graph
Graph createGraph() {
    Graph graph;
    graph.numCities = 0;
    graph.numRoads = 0;
    return graph;
}

// Function to add a city to the graph
void addCity(Graph *graph, char *cityName) {
    strcpy(graph->cities[graph->numCities], cityName);
    graph->numCities++;
}

// Function to add a road to the graph
void addRoad(Graph *graph, char *city1, char *city2, int length) {
    strcpy(graph->roads[graph->numRoads].city1, city1);
    strcpy(graph->roads[graph->numRoads].city2, city2);
    graph->roads[graph->numRoads].length = length;
    graph->numRoads++;
}

// Function to check if a route is valid and calculate its length
int calculateRouteLength(Graph *graph, char *route[], int routeLength) {
    int length = 0;
    for (int i = 0; i < routeLength - 1; i++) {
        int found = 0;
        for (int j = 0; j < graph->numRoads; j++) {
            if (strcmp(graph->roads[j].city1, route[i]) == 0 && strcmp(graph->roads[j].city2, route[i + 1]) == 0) {
                length += graph->roads[j].length;
                found = 1;
                break;
            }
        }
        if (!found) {
            return -1;
        }
        if (i > 0 && strcmp(route[i], route[i - 1]) == 0) {
            return -1;
        }
    }
    if (strcmp(route[0], route[routeLength - 1]) == 0) {
        return -1;
    }
    return length;
}

int main() {
    int numCities;
    scanf("%d", &numCities);
    getchar(); // Consume newline character
    Graph graph = createGraph();
    for (int i = 0; i < numCities; i++) {
        char cityName[MAX_CITY_NAME_LENGTH];
        fgets(cityName, MAX_CITY_NAME_LENGTH, stdin);
        cityName[strcspn(cityName, "\n")] = 0; // Remove newline character
        addCity(&graph, cityName);
    }
    int numRoads;
    scanf("%d", &numRoads);
    getchar(); // Consume newline character
    for (int i = 0; i < numRoads; i++) {
        char city1[MAX_CITY_NAME_LENGTH], city2[MAX_CITY_NAME_LENGTH];
        int length;
        scanf("%s %s %d", city1, city2, &length);
        getchar(); // Consume newline character
        addRoad(&graph, city1, city2, length);
    }
    int numRoutes;
    scanf("%d", &numRoutes);
    getchar(); // Consume newline character
    for (int i = 0; i < numRoutes; i++) {
        int routeLength;
        scanf("%d", &routeLength);
        getchar(); // Consume newline character
        char *route[routeLength];
        for (int j = 0; j < routeLength; j++) {
            route[j] = (char *)malloc(MAX_CITY_NAME_LENGTH * sizeof(char));
            fgets(route[j], MAX_CITY_NAME_LENGTH, stdin);
            route[j][strcspn(route[j], "\n")] = 0; // Remove newline character
        }
        int length = calculateRouteLength(&graph, route, routeLength);
        if (length == -1) {
            printf("ERROR\n");
        } else {
            printf("%d\n", length);
        }
        for (int j = 0; j < routeLength; j++) {
            free(route[j]);
        }
    }
    return 0;
}

