#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
using namespace std;

// Structure to represent a road
struct Road {
    string city1;
    string city2;
    int length;
};

// Structure to represent a graph
struct Graph {
    vector<string> cities;
    vector<Road> roads;
};

// Function to create a new graph
Graph createGraph() {
    Graph graph;
    return graph;
}

// Function to add a city to the graph
void addCity(Graph &graph, string cityName) {
    graph.cities.push_back(cityName);
}

// Function to add a road to the graph
void addRoad(Graph &graph, string city1, string city2, int length) {
    Road road;
    road.city1 = city1;
    road.city2 = city2;
    road.length = length;
    graph.roads.push_back(road);
}

// Function to check if a route is valid and calculate its length
int calculateRouteLength(Graph &graph, vector<string> route) {
    int length = 0;
    for (int i = 0; i < route.size() - 1; i++) {
        for (Road road : graph.roads) {
            if (road.city1 == route[i] && road.city2 == route[i + 1]) {
                length += road.length;
                break;
            }
        }
        if (length == 0) {
            return -1;
        }
        if (i > 0 && route[i] == route[i - 1]) {
            return -1;
        }
    }
    if (route[0] == route[route.size() - 1]) {
        return -1;
    }
    return length;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int numCities;
    cin >> numCities;
    cin.ignore();
    Graph graph = createGraph();
    for (int i = 0; i < numCities; i++) {
        string cityName;
        getline(cin, cityName);
        addCity(graph, cityName);
    }
    int numRoads;
    cin >> numRoads;
    cin.ignore();
    for (int i = 0; i < numRoads; i++) {
        string city1, city2;
        int length;
        cin >> city1 >> city2 >> length;
        cin.ignore();
        addRoad(graph, city1, city2, length);
    }
    int numRoutes;
    cin >> numRoutes;
    cin.ignore();
    for (int i = 0; i < numRoutes; i++) {
        int routeLength;
        cin >> routeLength;
        cin.ignore();
        vector<string> route(routeLength);
        for (int j = 0; j < routeLength; j++) {
            getline(cin, route[j]);
        }
        int length = calculateRouteLength(graph, route);
        if (length == -1) {
            cout << "ERROR" << endl;
        } else {
            cout << length << endl;
        }
    }
    return 0;
}

