import java.util.Scanner;
import java.util.ArrayList;
import java.util.HashMap;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int numCities = scanner.nextInt();
        scanner.nextLine();
        ArrayList<String> cities = new ArrayList<>();
        for (int i = 0; i < numCities; i++) {
            cities.add(scanner.nextLine());
        }
        int numRoads = scanner.nextInt();
        scanner.nextLine();
        HashMap<String, HashMap<String, Integer>> roads = new HashMap<>();
        for (int i = 0; i < numRoads; i++) {
            String city1 = scanner.next();
            String city2 = scanner.next();
            int length = scanner.nextInt();
            scanner.nextLine();
            if (!roads.containsKey(city1)) {
                roads.put(city1, new HashMap<>());
            }
            roads.get(city1).put(city2, length);
        }
        int numRoutes = scanner.nextInt();
        scanner.nextLine();
        for (int i = 0; i < numRoutes; i++) {
            int routeLength = scanner.nextInt();
            scanner.nextLine();
            String[] route = new String[routeLength];
            for (int j = 0; j < routeLength; j++) {
                route[j] = scanner.nextLine();
            }
            int length = calculateRouteLength(roads, route);
            if (length == -1) {
                System.out.println("ERROR");
            } else {
                System.out.println(length);
            }
        }
    }

    public static int calculateRouteLength(HashMap<String, HashMap<String, Integer>> roads, String[] route) {
        int length = 0;
        for (int i = 0; i < route.length - 1; i++) {
            if (roads.containsKey(route[i]) && roads.get(route[i]).containsKey(route[i + 1])) {
                length += roads.get(route[i]).get(route[i + 1]);
            } else {
                return -1;
            }
            if (i > 0 && route[i].equals(route[i - 1])) {
                return -1;
            }
        }
        if (route[0].equals(route[route.length - 1])) {
            return -1;
        }
        return length;
    }
}

